//! Auto-generated by the spec-word-compliance workflow for area
//! "OPC physical package (ZIP): structural validity, part-name constraints,
//! feature restrictions".
//!
//! Each `#[test]` encodes a normative rule from ISO/IEC 29500-2 (OPC) /
//! ECMA-376 Part 1 §11.2 about the physical ZIP package: item-name mapping,
//! required package items, ZIP feature restrictions (Annex B), and
//! consumption tolerance (data descriptors, archive comments).
//!
//! A FAILING assertion here is a real Word-compliance gap in stemma (the
//! engine diverges from what Word produces or consumes) — do NOT weaken the
//! assertion to make it pass.
//!
//! Coverage spans the OPC physical-package rules end to end: canonical
//! content-type Override for a WML extra part, ASCII part-name positive form,
//! ASCII case-insensitive Default / Override matching, the case-mismatched-part
//! roundtrip-emits-one-entry rule, duplicate-part rejection, and two checks
//! against real Word's open behavior.

use std::io::{Cursor, Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;
use zip::write::FileOptions;

// ---------------------------------------------------------------------------
// Prelude: package plumbing
// ---------------------------------------------------------------------------

const W_NS: &str = "http://schemas.openxmlformats.org/wordprocessingml/2006/main";

fn document_xml_for(body_xml: &str) -> String {
    format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:document xmlns:w="{W_NS}"><w:body>{body_xml}</w:body></w:document>"#
    )
}

fn content_types_for(extra_parts: &[(&str, &str)]) -> String {
    let mut s = String::from(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let content_type = match *name {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            "word/settings.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.settings+xml"
            }
            other => panic!("test plumbing: no content type mapping for extra part {other}"),
        };
        s.push_str(&format!(
            r#"<Override PartName="/{name}" ContentType="{content_type}"/>"#
        ));
    }
    s.push_str("</Types>");
    s
}

fn package_rels() -> &'static str {
    r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#
}

fn document_rels(extra_parts: &[(&str, &str)]) -> String {
    let mut s = String::from(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">"#,
    );
    for (i, (name, _)) in extra_parts.iter().enumerate() {
        let (rel_type, target) = match *name {
            "word/styles.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
                "styles.xml",
            ),
            "word/numbering.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
                "numbering.xml",
            ),
            "word/settings.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/settings",
                "settings.xml",
            ),
            other => panic!("test plumbing: no relationship mapping for extra part {other}"),
        };
        s.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    s.push_str("</Relationships>");
    s
}

/// Build a minimal valid .docx: [Content_Types].xml, _rels/.rels,
/// word/_rels/document.xml.rels, word/document.xml (+ any extra parts).
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = document_xml_for(body_xml);
    let content_types = content_types_for(extra_parts);
    let doc_rels = document_rels(extra_parts);

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: zip::write::FileOptions = zip::write::FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(package_rels().as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, content) in extra_parts {
            zip.start_file(*name, opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return the content of the item literally named
/// "word/document.xml" (ISO 29500-2 §7.3.4: part name minus the leading
/// slash). Reading strictly by this name is itself part of the observation:
/// if the writer used any other item name, this panics.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx))
        .expect("output must be a readable stored/DEFLATE ZIP (ISO 29500-2 §7.3.6 / Annex B)");
    let mut file = archive.by_name("word/document.xml").expect(
        "main document part must live at the ZIP item literally named 'word/document.xml' \
         (part name /word/document.xml minus the leading slash — ISO 29500-2 §7.3.4)",
    );
    let mut s = String::new();
    file.read_to_string(&mut s)
        .expect("word/document.xml must inflate to UTF-8 text");
    s
}

/// Parse -> serialize with default options -> return the re-serialized
/// word/document.xml as a String.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("Document::parse");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("Document::serialize");
    document_xml_of(&out)
}

/// Assert stemma::api::validate reports no errors for these bytes.
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "{rule} — expected validation to report no errors, got issues: {:?}",
        report.issues
    );
}

// ---------------------------------------------------------------------------
// Hand-crafted ZIP writer (streaming/bit-3 entries; not expressible via the
// zip crate's writer, which always back-patches the local header).
// ---------------------------------------------------------------------------

/// Bitwise CRC-32 (IEEE 802.3 polynomial, reflected), as used by ZIP.
fn crc32(data: &[u8]) -> u32 {
    let mut crc: u32 = 0xFFFF_FFFF;
    for &byte in data {
        crc ^= byte as u32;
        for _ in 0..8 {
            if crc & 1 != 0 {
                crc = (crc >> 1) ^ 0xEDB8_8320;
            } else {
                crc >>= 1;
            }
        }
    }
    !crc
}

fn put_u16(buf: &mut Vec<u8>, v: u16) {
    buf.extend_from_slice(&v.to_le_bytes());
}
fn put_u32(buf: &mut Vec<u8>, v: u32) {
    buf.extend_from_slice(&v.to_le_bytes());
}

/// Build a ZIP where every entry is written in streaming mode: general-purpose
/// bit 3 set, crc/sizes zeroed in the local file header, real values in a
/// signed data descriptor (0x08074b50) after the data, and correct values in
/// the central directory. Entries are STORED (method 0 — Annex B Table B.4
/// permits stored alongside DEFLATE).
fn make_zip_with_data_descriptors(entries: &[(&str, &[u8])]) -> Vec<u8> {
    let mut out = Vec::new();
    let mut central: Vec<(String, u32, u32, u32)> = Vec::new(); // name, crc, size, local offset

    for (name, data) in entries {
        let offset = out.len() as u32;
        let crc = crc32(data);
        let size = data.len() as u32;
        // Local file header — bit 3 set, crc/sizes zeroed.
        put_u32(&mut out, 0x0403_4b50);
        put_u16(&mut out, 20); // version needed
        put_u16(&mut out, 0x0008); // general purpose flags: bit 3 (data descriptor)
        put_u16(&mut out, 0); // method: stored
        put_u16(&mut out, 0); // mod time
        put_u16(&mut out, 0); // mod date
        put_u32(&mut out, 0); // crc-32 (zeroed under bit 3)
        put_u32(&mut out, 0); // compressed size (zeroed under bit 3)
        put_u32(&mut out, 0); // uncompressed size (zeroed under bit 3)
        put_u16(&mut out, name.len() as u16);
        put_u16(&mut out, 0); // extra len
        out.extend_from_slice(name.as_bytes());
        out.extend_from_slice(data);
        // Data descriptor with the optional 0x08074b50 signature.
        put_u32(&mut out, 0x0807_4b50);
        put_u32(&mut out, crc);
        put_u32(&mut out, size); // compressed size (stored => equal)
        put_u32(&mut out, size); // uncompressed size
        central.push((name.to_string(), crc, size, offset));
    }

    let cd_offset = out.len() as u32;
    for (name, crc, size, offset) in &central {
        put_u32(&mut out, 0x0201_4b50);
        put_u16(&mut out, 20); // version made by
        put_u16(&mut out, 20); // version needed
        put_u16(&mut out, 0x0008); // flags: bit 3
        put_u16(&mut out, 0); // method: stored
        put_u16(&mut out, 0); // mod time
        put_u16(&mut out, 0); // mod date
        put_u32(&mut out, *crc);
        put_u32(&mut out, *size);
        put_u32(&mut out, *size);
        put_u16(&mut out, name.len() as u16);
        put_u16(&mut out, 0); // extra len
        put_u16(&mut out, 0); // comment len
        put_u16(&mut out, 0); // disk number start
        put_u16(&mut out, 0); // internal attrs
        put_u32(&mut out, 0); // external attrs
        put_u32(&mut out, *offset);
        out.extend_from_slice(name.as_bytes());
    }
    let cd_size = out.len() as u32 - cd_offset;
    // End of central directory.
    put_u32(&mut out, 0x0605_4b50);
    put_u16(&mut out, 0); // disk
    put_u16(&mut out, 0); // disk with CD
    put_u16(&mut out, central.len() as u16);
    put_u16(&mut out, central.len() as u16);
    put_u32(&mut out, cd_size);
    put_u32(&mut out, cd_offset);
    put_u16(&mut out, 0); // comment len
    out
}

/// Build the standard four-part package as a streaming-mode (bit 3 /
/// data-descriptor) ZIP.
fn make_docx_with_data_descriptors(body_xml: &str) -> Vec<u8> {
    let document_xml = document_xml_for(body_xml);
    let content_types = content_types_for(&[]);
    let doc_rels = document_rels(&[]);
    make_zip_with_data_descriptors(&[
        ("[Content_Types].xml", content_types.as_bytes()),
        ("_rels/.rels", package_rels().as_bytes()),
        ("word/_rels/document.xml.rels", doc_rels.as_bytes()),
        ("word/document.xml", document_xml.as_bytes()),
    ])
}

/// Build the standard four-part package with a non-empty EOCD archive comment.
fn make_docx_with_archive_comment(body_xml: &str, comment: &str) -> Vec<u8> {
    let document_xml = document_xml_for(body_xml);
    let content_types = content_types_for(&[]);
    let doc_rels = document_rels(&[]);

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        zip.set_comment(comment);
        let opts: zip::write::FileOptions = zip::write::FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(package_rels().as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        zip.finish().unwrap();
    }
    buf
}

