#[test]
fn opc_main_document_zip_item_name_no_leading_slash_ascii() {
    // Rule: when producing a package, the Main Document part (part name
    // /word/document.xml) shall be stored as a single ZIP item whose item name
    // is the part name with the leading forward slash removed — exactly the
    // ASCII, forward-slash-separated name 'word/document.xml'.
    // Refs: ISO/IEC 29500-2 §7.3.2, §7.3.3, §7.3.4.
    let bytes = make_docx(
        "<w:p><w:r><w:t>opc item name probe</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let xml = reserialize(&bytes);
    assert!(
        xml.contains("opc item name probe"),
        "§7.3.4: producer shall map part name /word/document.xml to the ZIP item \
         'word/document.xml' (leading '/' removed, ASCII, unique per §7.3.3); the probe text \
         must be readable from the item by exactly that name — expected XML to contain \
         'opc item name probe'"
    );
    assert!(
        xml.contains("<w:document"),
        "§7.3.2: a non-interleaved part is a single ZIP item; the complete main-document \
         stream (starting at its root element) must come back from the single item \
         'word/document.xml' — expected XML to contain '<w:document'"
    );
}

#[test]
fn opc_minimal_wordprocessingml_package_opens_clean() {
    // Rule: a package containing only the content-type item, the package
    // relationship item pointing at one Main Document part, and a Main
    // Document whose body is a single empty paragraph is the MINIMAL
    // conformant WordprocessingML package; a Word-aligned validator shall
    // report no errors for it.
    // Refs: ECMA-376/ISO 29500-1 §11.2, ISO/IEC 29500-2 §7.2.2.
    let bytes = make_docx("<w:p/><w:sectPr/>", &[]);
    assert_opens_clean(
        &bytes,
        "§11.2: the package-relationship item + content-type item + one Main Document part \
         (empty-paragraph body) constitute the minimal conformant WordprocessingML package; \
         Word opens it without repair, so stemma::api::validate must report no errors",
    );
}

#[test]
fn opc_package_production_deflate_or_stored_only_no_encryption() {
    // Rule: a produced ZIP-based package shall not include encryption and
    // shall not use any compression method other than DEFLATE (or stored),
    // so every conforming consumer can fully inflate the main part's stream.
    // Refs: ISO/IEC 29500-2 §7.3.1, §7.3.6, Annex B Tables B.3/B.4.
    let bytes = make_docx(
        "<w:p><w:r><w:t>deflate readability probe</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let xml = reserialize(&bytes);
    assert!(
        xml.contains("deflate readability probe"),
        "§7.3.6: production may use no encryption and no compression except DEFLATE \
         (Annex B Tables B.3/B.4); the reserialized main part must inflate completely with a \
         stored/DEFLATE-only reader and yield the original run text — expected XML to contain \
         'deflate readability probe'"
    );
    assert!(
        xml.contains("</w:document>"),
        "§7.3.6 + Annex B Table B.4: the item's data must be a plain stored/DEFLATE stream \
         (no patched data sets, no Deflate64) so inflation reaches the end of the part — \
         expected XML to contain '</w:document>'"
    );
}

#[test]
fn zip_data_descriptor_entries_open_clean() {
    // Rule: Word opens a DOCX whose ZIP entries were written in streaming mode
    // (general-purpose bit 3 set, crc/sizes zeroed in the local file header,
    // correct values in a data descriptor after the data); stemma must parse
    // and validate such a package cleanly, taking entry metadata from the data
    // descriptor / central directory rather than the zeroed local header.
    // Refs: ISO/IEC 29500-2 Annex B Table B.1 (data descriptor: consumption
    // Yes), Table B.5 (general-purpose bit 3: consumption Yes).
    let bytes =
        make_docx_with_data_descriptors("<w:p><w:r><w:t>Hello OPC</w:t></w:r></w:p><w:sectPr/>");
    assert_opens_clean(
        &bytes,
        "Annex B Tables B.1/B.5: data descriptor and general-purpose bit 3 are \
         consumption=Yes — 'a package implementer shall not fail to read the ZIP file \
         containing this record or field'; a bit-3 streaming package is a conformant \
         physical package and must validate with no errors",
    );
    let doc = Document::parse(&bytes).expect(
        "Annex B Table B.5 bit 3: a conformant consumer shall not fail to read a \
         streaming-mode (data-descriptor) package — Document::parse must succeed",
    );
    let text = doc.read_accepted().expect("read_accepted").to_text();
    assert_eq!(
        text.trim(),
        "Hello OPC",
        "Annex B Table B.5 bit 3: the correct sizes/crc live in the data descriptor \
         following the compressed data; a conformant consumer decodes the entry content \
         regardless, so the document text must read back intact"
    );
}

#[test]
fn zip_eocd_archive_comment_tolerated() {
    // Rule: Word opens a DOCX whose end-of-central-directory record carries a
    // non-empty ZIP file comment; the comment is read-tolerated (and ignored),
    // never a reason to refuse the package.
    // Refs: ISO/IEC 29500-2 Annex B Table B.2 (ZIP file comment: consumption
    // Yes, production No).
    let bytes = make_docx_with_archive_comment(
        "<w:p><w:r><w:t>Hello OPC</w:t></w:r></w:p><w:sectPr/>",
        "repacked by a tool that loves archive comments",
    );
    assert_opens_clean(
        &bytes,
        "Annex B Table B.2: the EOCD ZIP file comment field is consumption=Yes — a \
         commented archive 'shall not fail to read', so validation must report no errors",
    );
    let doc = Document::parse(&bytes).expect(
        "Annex B Table B.2: a consumer shall not fail to read an archive with an EOCD \
         comment — Document::parse must succeed",
    );
    let text = doc.read_accepted().expect("read_accepted").to_text();
    assert_eq!(
        text.trim(),
        "Hello OPC",
        "Annex B Table B.2: the EOCD comment may be ignored but the package contents are \
         unaffected; all parts remain readable, so the accepted text equals the document text"
    );
}

#[test]
fn opc_body_zero_blocks_only_sectpr_opens_clean() {
    // Rule: a main document whose w:body contains zero block-level elements
    // (only the trailing w:sectPr) is schema-valid WordprocessingML
    // (CT_Body: EG_BlockLevelElts minOccurs=0, sectPr optional) inside a
    // conformant OPC package; Word opens it without repair, and the engine
    // must keep the body's final sectPr on re-save.
    // Refs: ECMA-376 Part 1 §11.2, ISO 29500-2 §7.3, wml.xsd CT_Body.
    let bytes = make_docx("<w:sectPr/>", &[]);
    assert_opens_clean(
        &bytes,
        "wml.xsd CT_Body: EG_BlockLevelElts has minOccurs=0, so a body whose only child is \
         w:sectPr is schema-valid; Word opens it without repair (displays one empty \
         paragraph), therefore stemma::api::validate must report no errors",
    );
    let xml = reserialize(&bytes);
    assert!(
        xml.contains("<w:sectPr"),
        "wml.xsd CT_Body sequence ends with an optional sectPr; stemma's serializer \
         model-rebuilds the body-level sectPr and must not drop it (or fail) when the body \
         has zero blocks — expected re-serialized XML to contain '<w:sectPr' (synthesizing \
         an empty w:p alongside it is acceptable; this assertion only pins sectPr survival)"
    );
}

#[test]
fn opc_resave_content_type_item_and_unprefixed_main_part() {
    // Rule: every package the engine saves must remain a conformant OPC ZIP:
    // it contains the content-type item [Content_Types].xml and stores the
    // Main Document part under the slash-free, ASCII, unique ZIP item name
    // word/document.xml, so Word reopens the saved file without repair.
    // Refs: ECMA §11.2, ISO 29500-2 §7.3.3/§7.3.4/§7.3.7, MS-OE376 §2.1.8.
    let bytes = make_docx(
        "<w:p><w:r><w:t>OPC_RT_MARKER</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let doc = Document::parse(&bytes).expect("Document::parse");
    let saved = doc
        .serialize(&ExportOptions::default())
        .expect("Document::serialize");
    let xml = document_xml_of(&saved);
    assert!(
        xml.contains("OPC_RT_MARKER"),
        "ISO 29500-2 §7.3.4: the saved main part must live at ZIP item name \
         'word/document.xml' (leading slash removed, ASCII, unique per §7.3.3); reading the \
         re-serialized package's item by exactly that name must yield the marker text — \
         expected XML to contain 'OPC_RT_MARKER'"
    );
    assert_opens_clean(
        &saved,
        "ECMA §11.2 + ISO 29500-2 §7.3.7: validating the RE-SERIALIZED bytes — the saved \
         package must still contain the package-relationship item, the [Content_Types].xml \
         content-type item (declaring wordprocessingml.document.main+xml per MS-OE376 \
         §2.1.8), and the Main Document part, otherwise Word shows the repair prompt on \
         reopen",
    );
}

#[test]
fn zip_item_name_mapping_strips_leading_slash_on_save() {
    // Rule: when writing a package, the main document part (logical name
    // /word/document.xml) must be stored as the ZIP item 'word/document.xml':
    // leading slash removed, forward-slash separators, ASCII name — so a
    // conforming OPC/Word reader can resolve the part after stemma serializes.
    // Refs: ISO/IEC 29500-2 §7.3.3/§7.3.4, ECMA-376 Part 1 §11.2.
    let bytes = make_docx(
        "<w:p><w:r><w:t>ZipItemNameMarker</w:t></w:r></w:p><w:sectPr/>",
        &[],
    );
    let xml = reserialize(&bytes);
    assert!(
        xml.contains("ZipItemNameMarker"),
        "§7.3.4: the serialized package must store the main document at ZIP item name \
         'word/document.xml' (leading slash stripped, '/' separators, ASCII per §7.3.3); \
         the harness reads the re-serialized part strictly by that name — expected XML to \
         contain 'ZipItemNameMarker'"
    );
    assert_opens_clean(
        &bytes,
        "ECMA-376 Part 1 §11.2: the input is a conformant package (content-type item, \
         package-relationship item, Main Document part); the validator must not flag it",
    );
}

