const NUMBERING_CONTENT_TYPE: &str =
    "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml";

/// True iff `validate` reports no errors (opens clean). The opens-clean tests
/// above use `assert_opens_clean`; the duplicate-part rules below need to assert the
/// NEGATIVE (a package that must NOT open clean), so they need the bool form.
fn opens_clean(bytes: &[u8]) -> bool {
    let report = stemma::api::validate(bytes);
    report.ok && report.issues.is_empty()
}

/// Render a `ValidationReport`'s issues for an assertion message.
fn validation_issues(bytes: &[u8]) -> String {
    let report = stemma::api::validate(bytes);
    format!(
        "ok={} issues={:?}",
        report.ok,
        report
            .issues
            .iter()
            .map(|i| format!("{:?}: {}", i.code, i.message))
            .collect::<Vec<_>>()
    )
}

/// Count ZIP entries with exactly `name`.
fn count_zip_entries_named(bytes: &[u8], name: &str) -> usize {
    let mut archive = zip::ZipArchive::new(Cursor::new(bytes)).expect("open zip");
    let mut count = 0;
    for i in 0..archive.len() {
        let file = archive.by_index(i).expect("zip entry");
        if file.name() == name {
            count += 1;
        }
    }
    count
}

/// Like `make_docx` but the xml Default extension is UPPER-CASE ("XML"). Tests
/// ASCII case-insensitive Default matching (OPC §7.2.3).
fn make_docx_with_upper_xml_default(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = document_xml_for(body_xml);
    // content_types_for emits the lower-case xml Default; rewrite it to upper-case.
    let content_types = content_types_for(extra_parts)
        .replace(r#"Default Extension="xml""#, r#"Default Extension="XML""#);
    let doc_rels = document_rels(extra_parts);

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(package_rels().as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, content) in extra_parts {
            zip.start_file(*name, opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// A package whose body part is stored at `word/Document.xml` (upper-case D),
/// content-typed by Override `/word/document.xml` and targeted by the
/// relationship `word/Document.xml`. Tests ASCII case-insensitive Override
/// matching (OPC §7.2.3) and case-equivalent part resolution (OPC §6.2).
fn make_docx_with_uppercase_document_partname(body_xml: &str) -> Vec<u8> {
    let document_xml = document_xml_for(body_xml);
    let content_types = content_types_for(&[]);
    // Relationship target points at the upper-case stored part name.
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/Document.xml"/></Relationships>"#;
    let doc_rels = document_rels(&[]);

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        // The document part's rels live alongside it, case-matched.
        zip.start_file("word/_rels/Document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/Document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        zip.finish().unwrap();
    }
    buf
}

/// A package physically containing TWO ZIP items both named word/document.xml
/// (the second with different body text). OPC §6.2.2 / §7.3.3 forbid this.
fn make_docx_with_duplicate_document() -> Vec<u8> {
    let doc_a =
        document_xml_for("<w:p><w:r><w:t>First document part.</w:t></w:r></w:p><w:sectPr/>");
    let doc_b =
        document_xml_for("<w:p><w:r><w:t>Second document part.</w:t></w:r></w:p><w:sectPr/>");
    let content_types = content_types_for(&[]);
    let doc_rels = document_rels(&[]);

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(package_rels().as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        // First entry.
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(doc_a.as_bytes()).unwrap();
        // Duplicate entry — same name, different content.
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(doc_b.as_bytes()).unwrap();
        zip.finish().unwrap();
    }
    buf
}

#[test]
fn numbering_part_emits_canonical_content_type_override() {
    // Rule: every WML part (e.g. word/numbering.xml) must be content-typed by a
    // matching Override carrying its canonical content type; the generic xml
    // Default is not sufficient, so the package with the numbering Override must
    // open clean. Refs: ECMA-376 Part 1 §11.2/§15.2, OPC §7.2.3.
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>First numbered item.</w:t></w:r></w:p><w:sectPr/>"#;
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);
    assert!(
        opens_clean(&b),
        "Every WML part (e.g. word/numbering.xml) must be content-typed by a matching Override \
         carrying its canonical content type ({NUMBERING_CONTENT_TYPE}); the generic xml Default \
         is not sufficient, so the package with the numbering Override must open clean (ECMA-376 \
         Part 1 §11.2/§15.2, OPC §7.2.3). Got: {}",
        validation_issues(&b)
    );
}

#[test]
fn non_ascii_part_names_not_loadable_by_word() {
    // POSITIVE side of the rule: the conformant, Word-loadable form uses
    // ASCII-only part names and must open clean. (The negative — a non-ASCII
    // part name being rejected — is the oracle question recorded on the spec.)
    let body = r#"<w:p><w:r><w:t>All part names in this package are ASCII and Word-loadable.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        opens_clean(&b),
        "Word will not load a package with non-ASCII part names; the conformant Word-loadable form \
         uses ASCII-only part names and must validate clean (MS-OI29500 §2.1.1749, OPC §7.3.3). \
         Got: {}",
        validation_issues(&b)
    );
}

#[test]
fn content_type_default_extension_match_is_case_insensitive() {
    // Default Extension matching is ASCII case-insensitive, so Default
    // Extension="XML" (upper-case) must cover word/document.xml and
    // word/styles.xml; every part is content-typed and the package opens clean.
    // Refs: OPC §7.2.3, ECMA-376 Part 1 §11.2.
    let body = r#"<w:p><w:r><w:t>Case-insensitive extension match.</w:t></w:r></w:p><w:sectPr/>"#;
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"></w:styles>"#;
    let b = make_docx_with_upper_xml_default(body, &[("word/styles.xml", styles)]);
    assert!(
        opens_clean(&b),
        "Default Extension matching is ASCII case-insensitive, so Default Extension=\"XML\" \
         (upper-case) must cover word/document.xml and word/styles.xml; every part is content-typed \
         and the package must open clean — no I-CT-001/002 (OPC §7.2.3, ECMA-376 Part 1 §11.2). \
         Got: {}",
        validation_issues(&b)
    );
}

#[test]
fn content_type_override_match_is_ascii_case_insensitive() {
    // ZIP item stored as word/Document.xml; its Override is /word/document.xml.
    // OPC §7.2.3 mandates ASCII case-insensitive PartName matching, so the part
    // is content-typed and the package opens clean. A case-sensitive validator
    // would falsely report I-CT-001 — that divergence is what this hunts.
    let body = r#"<w:p><w:r><w:t>Body served by a case-mismatched main-document part name.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx_with_uppercase_document_partname(body);
    assert!(
        opens_clean(&b),
        "Override PartName matching is ASCII case-insensitive, so a part stored as \
         word/Document.xml is content-typed by Override /word/document.xml; the package must open \
         clean — no I-CT-001 (OPC §7.2.3, §6.2.2). Got: {}",
        validation_issues(&b)
    );
}

#[test]
fn uppercase_document_partname_roundtrips_without_duplicate_part() {
    // Parse the case-mismatched package and run a full serialize. Part-name
    // resolution is ASCII case-insensitive (OPC §6.2), so the serializer must
    // recognize word/Document.xml as THE main document part: the output must
    // carry exactly one case-equivalent main-document entry, never a lower-case
    // sibling (which would violate part-name uniqueness, OPC §7.3).
    let body = r#"<w:p><w:r><w:t>Case-mismatched main document, full roundtrip.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx_with_uppercase_document_partname(body);
    let doc = Document::parse(&b).expect("a case-mismatched main-document part name must parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");

    let mut archive = zip::ZipArchive::new(Cursor::new(out.as_slice())).expect("open zip");
    let mut equivalent_entries = Vec::new();
    for i in 0..archive.len() {
        let file = archive.by_index(i).expect("zip entry");
        if file.name().eq_ignore_ascii_case("word/document.xml") {
            equivalent_entries.push(file.name().to_string());
        }
    }
    assert_eq!(
        equivalent_entries.len(),
        1,
        "exactly one main-document part after roundtrip (OPC §6.2, §7.3); got {equivalent_entries:?}"
    );
    assert!(
        opens_clean(&out),
        "the roundtripped package must validate clean. Got: {}",
        validation_issues(&out)
    );
}

// DocxArchive read fails loud with DocxError::DuplicatePartName on a duplicate
// ZIP entry name (OPC §6.2.2) rather than silently collapsing to
// last-writer-wins, so validate reports the package as not-clean like Word.
#[test]
fn duplicate_part_name_rejected() {
    // Build a package with TWO ZIP items both named word/document.xml. OPC
    // §6.2.2 / §7.3.3 forbid this; Word reports corruption. CORRECT behaviour is
    // to flag it — so opens_clean must be FALSE. If this assertion FAILS (i.e.
    // opens_clean is true), stemma swallowed the duplicate and diverges.
    let b = make_docx_with_duplicate_document();
    assert!(
        !opens_clean(&b),
        "Two ZIP items named word/document.xml violate part-name uniqueness; Word reports \
         corruption. stemma must NOT report the package as clean — if it does, it silently \
         collapsed the duplicate and diverges from Word (OPC §6.2.2, §7.3.3). Got: {}",
        validation_issues(&b)
    );
}

#[test]
fn duplicate_part_names_are_rejected() {
    // Positive side: a package with exactly ONE word/document.xml entry must
    // validate clean, AND the re-serialized package must emit exactly one
    // word/document.xml entry (the serializer must never duplicate a part on
    // roundtrip).
    let body = r#"<w:p><w:r><w:t>A package with exactly one document part validates clean.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        opens_clean(&b),
        "A package with exactly one word/document.xml must validate clean (OPC §7.3.3, §6.2.2). \
         Got: {}",
        validation_issues(&b)
    );
    let out = Document::parse(&b)
        .expect("parse")
        .serialize(&ExportOptions::default())
        .expect("serialize");
    let count = count_zip_entries_named(&out, "word/document.xml");
    assert_eq!(
        count, 1,
        "The serializer must emit exactly one word/document.xml entry on roundtrip; emitting two \
         would violate ZIP item-name uniqueness (OPC §7.3.3, §6.2.2). Got {count} entries."
    );
}
